# server.py
from concurrent import futures
import time
import hashlib
import secrets

import auth_pb2_grpc
import data_pb2_grpc


class AuthServiceImpl(auth_pb2_grpc.AuthServiceServicer):
    def __init__(self):
        self.users = {}
        self.tokens = {}
        self.user_id_counter = 1

    def Login(self, request, context):
        username = request.username
        password = request.password
        
        if username in self.users:
            stored_hash = self.users[username]['password']
            password_hash = hashlib.sha256(password.encode()).hexdigest()
            
            if password_hash == stored_hash:
                token = secrets.token_urlsafe(32)
                user_id = self.users[username]['id']
                self.tokens[token] = {'user_id': user_id, 'username': username}
                
                return auth_pb2.LoginResponse(
                    success=True,
                    token=token,
                    message="Login successful"
                )
        
        return auth_pb2.LoginResponse(
            success=False,
            token="",
            message="Invalid username or password"
        )

    def Register(self, request, context):
        username = request.username
        password = request.password
        email = request.email
        
        if username in self.users:
            return auth_pb2.RegisterResponse(
                success=False,
                message="Username already exists",
                user_id=0
            )
        
        password_hash = hashlib.sha256(password.encode()).hexdigest()
        user_id = self.user_id_counter
        self.user_id_counter += 1
        
        self.users[username] = {
            'id': user_id,
            'password': password_hash,
            'email': email,
            'created_at': int(time.time())
        }
        
        return auth_pb2.RegisterResponse(
            success=True,
            message="Registration successful",
            user_id=user_id
        )

    def ValidateToken(self, request, context):
        token = request.token
        
        if token in self.tokens:
            token_data = self.tokens[token]
            return auth_pb2.ValidateTokenResponse(
                valid=True,
                user_id=token_data['user_id'],
                username=token_data['username']
            )
        
        return auth_pb2.ValidateTokenResponse(
            valid=False,
            user_id=0,
            username=""
        )


class DataServiceImpl(data_pb2_grpc.DataServiceServicer):
    def __init__(self, auth_service):
        self.auth_service = auth_service
        self.records = []
        self.record_id_counter = 1

    def GetUser(self, request, context):
        user_id = request.user_id
        
        for username, user_data in self.auth_service.users.items():
            if user_data['id'] == user_id:
                user = data_pb2.User(
                    id=user_data['id'],
                    username=username,
                    email=user_data['email'],
                    created_at=user_data['created_at']
                )
                return data_pb2.GetUserResponse(
                    success=True,
                    user=user,
                    message="User found"
                )
        
        return data_pb2.GetUserResponse(
            success=False,
            message="User not found"
        )

    def GetUsers(self, request, context):
        limit = request.limit if request.limit > 0 else 10
        offset = request.offset if request.offset >= 0 else 0
        
        users_list = []
        for username, user_data in list(self.auth_service.users.items())[offset:offset+limit]:
            user = data_pb2.User(
                id=user_data['id'],
                username=username,
                email=user_data['email'],
                created_at=user_data['created_at']
            )
            users_list.append(user)
        
        return data_pb2.GetUsersResponse(
            users=users_list,
            total=len(self.auth_service.users)
        )

    def CreateRecord(self, request, context):
        record_id = self.record_id_counter
        self.record_id_counter += 1
        
        record = {
            'id': record_id,
            'user_id': request.user_id,
            'title': request.title,
            'content': request.content,
            'created_at': int(time.time())
        }
        self.records.append(record)
        
        return data_pb2.CreateRecordResponse(
            success=True,
            record_id=record_id,
            message="Record created successfully"
        )

    def GetRecords(self, request, context):
        user_id = request.user_id
        limit = request.limit if request.limit > 0 else 10
        
        user_records = [r for r in self.records if r['user_id'] == user_id][:limit]
        
        records_list = []
        for record in user_records:
            rec = data_pb2.Record(
                id=record['id'],
                user_id=record['user_id'],
                title=record['title'],
                content=record['content'],
                created_at=record['created_at']
            )
            records_list.append(rec)
        
        return data_pb2.GetRecordsResponse(
            records=records_list,
            total=len([r for r in self.records if r['user_id'] == user_id])
        )


def serve():
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    
    auth_service = AuthServiceImpl()
    data_service = DataServiceImpl(auth_service)
    
    auth_pb2_grpc.add_AuthServiceServicer_to_server(auth_service, server)
    data_pb2_grpc.add_DataServiceServicer_to_server(data_service, server)
    
    server.add_insecure_port('[::]:50051')
    server.start()
    print("gRPC Server started on port 50051")
    
    try:
        while True:
            time.sleep(86400)
    except KeyboardInterrupt:
        server.stop(0)


if __name__ == '__main__':
    serve()


# client.py
def run_client():
    channel = grpc.insecure_channel('localhost:50051')
    
    auth_stub = auth_pb2_grpc.AuthServiceStub(channel)
    data_stub = data_pb2_grpc.DataServiceStub(channel)
    
    print("=== Registering a new user ===")
    register_response = auth_stub.Register(
        auth_pb2.RegisterRequest(
            username="john_doe",
            password="password123",
            email="john@example.com"
        )
    )
    print(f"Register Response: {register_response.message}")
    print(f"User ID: {register_response.user_id}")
    
    print("\n=== Logging in ===")
    login_response = auth_stub.Login(
        auth_pb2.LoginRequest(
            username="john_doe",
            password="password123"
        )
    )
    print(f"Login Response: {login_response.message}")
    print(f"Token: {login_response.token[:20]}...")
    
    token = login_response.token
    
    print("\n=== Validating token ===")
    validate_response = auth_stub.ValidateToken(
        auth_pb2.ValidateTokenRequest(token=token)
    )
    print(f"Token valid: {validate_response.valid}")
    print(f"User ID: {validate_response.user_id}")
    print(f"Username: {validate_response.username}")
    
    user_id = validate_response.user_id
    
    print("\n=== Getting user details ===")
    user_response = data_stub.GetUser(
        data_pb2.GetUserRequest(user_id=user_id)
    )
    print(f"Success: {user_response.success}")
    print(f"User: {user_response.user.username}, Email: {user_response.user.email}")
    
    print("\n=== Creating a record ===")
    create_record_response = data_stub.CreateRecord(
        data_pb2.CreateRecordRequest(
            user_id=user_id,
            title="My First Record",
            content="This is the content of my first record"
        )
    )
    print(f"Record created: {create_record_response.message}")
    print(f"Record ID: {create_record_response.record_id}")
    
    print("\n=== Creating another record ===")
    data_stub.CreateRecord(
        data_pb2.CreateRecordRequest(
            user_id=user_id,
            title="My Second Record",
            content="This is the content of my second record"
        )
    )
    
    print("\n=== Getting user records ===")
    records_response = data_stub.GetRecords(
        data_pb2.GetRecordsRequest(
            user_id=user_id,
            limit=5
        )
    )
    print(f"Total records: {records_response.total}")
    for record in records_response.records:
        print(f"  Record {record.id}: {record.title}")
    
    print("\n=== Registering another user ===")
    auth_stub.Register(
        auth_pb2.RegisterRequest(
            username="jane_smith",
            password="password456",
            email="jane@example.com"
        )
    )
    
    print("\n=== Getting all users ===")
    users_response = data_stub.GetUsers(
        data_pb2.GetUsersRequest(limit=10, offset=0)
    )
    print(f"Total users: {users_response.total}")
    for user in users_response.users:
        print(f"  User {user.id}: {user.username} ({user.email})")
    
    channel.close()


if __name__ == '__main__':
    run_client()